"use client";

import { ark } from "@ark-ui/react/factory";
import type React from "react";
import { tv, type VariantProps } from "tailwind-variants";
import { cn } from "@/lib/utils";

export const announcementVariants = tv({
  base: [
    "inline-flex items-center gap-2",
    "px-3 py-1.5",
    "font-medium text-sm",
    "rounded-full border",
    "outline-none focus-visible:border-primary focus-visible:ring-[3px] focus-visible:ring-ring/32",
    "[&_svg]:size-4 [&_svg]:shrink-0",
    "[button&,a&]:cursor-pointer [button&,a&]:pointer-coarse:after:absolute [button&,a&]:pointer-coarse:after:size-full [button&,a&]:pointer-coarse:after:min-h-11 [button&,a&]:pointer-coarse:after:min-w-11",
  ],
  variants: {
    variant: {
      default: [
        "bg-input/4 dark:bg-input/32",
        "[&_svg]:text-muted-foreground",
        "[a&]:shadow-border/24 [a&]:shadow-xs",
        "[a&]:hover:bg-input/8",
      ],
      destructive: [
        "bg-destructive/4",
        "border-destructive/32",
        "[&_svg]:text-destructive",
        "[a&]:shadow-destructive/24 [a&]:shadow-xs",
        "[a&]:hover:bg-destructive/10",
      ],
      info: [
        "bg-info/4",
        "border-info/32",
        "[&_svg]:text-info",
        "[a&]:shadow-info/24 [a&]:shadow-xs",
        "[a&]:hover:bg-info/10",
      ],
      warning: [
        "bg-warning/4",
        "border-warning/32",
        "[&_svg]:text-warning",
        "[a&]:shadow-warning/24 [a&]:shadow-xs",
        "[a&]:hover:bg-warning/10",
      ],
      success: [
        "bg-success/4",
        "border-success/32",
        "[&_svg]:text-success",
        "[a&]:shadow-success/24 [a&]:shadow-xs",
        "[a&]:hover:bg-success/10",
      ],
    },
  },
  defaultVariants: {
    variant: "default",
  },
});

interface AnnouncementProps
  extends React.ComponentProps<typeof ark.div>,
    VariantProps<typeof announcementVariants> {}

export const Announcement = (props: AnnouncementProps) => {
  const { variant = "default", className, role, asChild, ...rest } = props;
  const resolvedRole = role ?? (asChild ? undefined : "status");

  return (
    <ark.div
      asChild={asChild}
      className={cn(announcementVariants({ variant }), className)}
      data-slot="announcement"
      {...(resolvedRole != null && { role: resolvedRole })}
      {...rest}
    />
  );
};

export const AnnouncementTag = (
  props: React.ComponentProps<typeof ark.span>
) => {
  const { className, ...rest } = props;

  return (
    <ark.span
      className={cn("font-medium text-xs opacity-90", className)}
      data-slot="announcement-tag"
      {...rest}
    />
  );
};

export const AnnouncementTitle = (
  props: React.ComponentProps<typeof ark.span>
) => {
  const { className, ...rest } = props;

  return (
    <ark.span
      className={cn("inline-flex items-center gap-1 font-medium", className)}
      data-slot="announcement-title"
      {...rest}
    />
  );
};
